it('fetches posts and authors efficiently', async () => {
  await createPosts(100); // Create 100 posts
  const queryCount = db.getQueryCount();
  await request(app).get('/posts').expect(200);
  const queriesExecuted = db.getQueryCount() - queryCount;
  expect(queriesExecuted).toBeLessThanOrEqual(2); // 1 for posts, 1 for authors
});

it('includes author data in response', async () => {
  const author = await createUser({ name: 'Alice' });
  await createPost({ title: 'Test', authorId: author.id });
  const res = await request(app).get('/posts').expect(200);
  expect(res.body[0].author).toMatchObject({ id: author.id, name: 'Alice' });
});

it('fetches comment authors efficiently', async () => {
  const post = await createPost({ title: 'Test' });
  await createComments(50, { postId: post.id }); // 50 comments
  const queryCount = db.getQueryCount();
  await request(app).get(`/posts/${post.id}`).expect(200);
  const queriesExecuted = db.getQueryCount() - queryCount;
  expect(queriesExecuted).toBeLessThanOrEqual(3); // 1 post, 1 comments, 1 authors
});
